// Cloudflared exposes Prometheus-style metrics at :2000/metrics.
// The gauge we care about is cloudflared_tunnel_ha_connections — the
// number of active tunnel connections to the CF edge. Healthy = >= 1.
//
// Response body is text (Prometheus text format), not JSON — grab it
// off the raw body if n8n wrapped it, otherwise fall back to $json.

const raw = $input.first().json;
const body = raw?.data || raw?.body || (typeof raw === 'string' ? raw : JSON.stringify(raw));

const grabGauge = (name) => {
  const re = new RegExp('^' + name + '\\s+([0-9.eE+-]+)', 'm');
  const m = body.match(re);
  return m ? Number(m[1]) : null;
};

const connections = grabGauge('cloudflared_tunnel_ha_connections') ?? 0;
const requestsTotal = grabGauge('cloudflared_tunnel_request_errors') ?? 0;
const tunnelUp = connections >= 1;

// Only post to MM on state change OR when triggered manually via webhook.
// Manual webhook is 'Webhook (manual check)'; anything else is the cron.
const triggerName = $execution.mode === 'trigger' ? 'cron' : 'webhook';
const forcePost = triggerName === 'webhook';

const emoji = tunnelUp ? ':large_green_circle:' : ':red_circle:';
const label = tunnelUp ? 'HEALTHY' : 'DOWN';

const message = [
  `${emoji} **Cloudflared tunnel** — ${label}`,
  `**Active connections:** ${connections}`,
  `**Cumulative request errors:** ${requestsTotal}`,
  `_(Checked at ${new Date().toISOString()})_`,
].join('\n');

return [{
  json: {
    tunnelUp,
    connections,
    requestsTotal,
    message,
    forcePost,
    // 'shouldPost' — the workflow's downstream branching will use this
    shouldPost: forcePost || !tunnelUp,
  }
}];
